# 从原脚本复制的函数
def convert_to_serializable(obj):
    """
    将不可JSON序列化的对象转换为可序列化的格式
    """
    #Generated By AI Start (Cursor)
    if obj is pd.NaT:
        return None
    try:
        if pd.isna(obj):
            return None
    except (TypeError, ValueError):
        pass
    #Generated By AI End (Cursor)
    if isinstance(obj, datetime):
        return obj.strftime('%Y-%m-%d %H:%M:%S')
    elif isinstance(obj, (pd.Timestamp,)):
        return obj.strftime('%Y-%m-%d %H:%M:%S') if not pd.isna(obj) else None
    else:
        return obj


def toon_escape_value(value):
    """
    对TOON格式的值进行转义处理
    - 如果值包含特殊字符（逗号、换行、冒号等），用双引号包裹
    - 如果值本身包含双引号，进行转义
    """
    if value is None:
        return "null"
    
    value_str = str(value)
    
    #Generated By AI Start (Cursor)
    needs_quotes = any(char in value_str for char in [',', '\n', '\r', ':', '"', '|', '\\'])
    #Generated By AI End (Cursor)
    
    # 检查是否是关键字（避免混淆）
    if value_str.lower() in ['true', 'false', 'null']:
        if not isinstance(value, bool) and value is not None:
            needs_quotes = True
    
    if needs_quotes:
        #Generated By AI Start (Cursor)
        escaped = value_str.replace('\\', '\\\\').replace('"', '\\"').replace('\n', '\\n').replace('\r', '\\r')
        #Generated By AI End (Cursor)
        return f'"{escaped}"'
    
    return value_str


def convert_to_toon(data):
    """
    将Python字典转换为TOON格式字符串
    TOON (Token-Oriented Object Notation) 是一种为LLM优化的紧凑格式
    """
    lines = []
    
    def format_simple_value(val, indent_level=0):
        """格式化简单值"""
        indent = "  " * indent_level
        if val is None:
            return "null"
        elif isinstance(val, bool):
            return "true" if val else "false"
        elif isinstance(val, (int, float)):
            return str(val)
        else:
            return toon_escape_value(val)
    
    def format_object(obj, indent_level=0):
        """格式化对象（字典）"""
        indent = "  " * indent_level
        result = []
        for key, value in obj.items():
            if value is None:
                result.append(f"{indent}{key}: null")
            elif isinstance(value, bool):
                result.append(f"{indent}{key}: {'true' if value else 'false'}")
            elif isinstance(value, (int, float)):
                result.append(f"{indent}{key}: {value}")
            elif isinstance(value, str):
                result.append(f"{indent}{key}: {toon_escape_value(value)}")
            elif isinstance(value, list):
                # 处理数组
                result.extend(format_array(key, value, indent_level))
            elif isinstance(value, dict):
                result.append(f"{indent}{key}:")
                result.extend(format_object(value, indent_level + 1).split('\n'))
        return '\n'.join(result)
    
    def format_array(key, arr, indent_level=0):
        """格式化数组 - TOON的核心优化"""
        indent = "  " * indent_level
        result = []
        
        if not arr:
            result.append(f"{indent}{key}[0]:")
            return result
        
        # 检查是否是对象数组（结构化数组）
        if all(isinstance(item, dict) for item in arr):
            # 收集所有可能的字段名（保持顺序）
            all_keys = []
            for item in arr:
                for k in item.keys():
                    if k not in all_keys:
                        all_keys.append(k)
            
            # 使用TOON表格格式: key[length]{field1, field2, ...}:
            fields_str = ", ".join(all_keys)
            result.append(f"{indent}{key}[{len(arr)}]{{{fields_str}}}:")
            
            # 每行一条记录
            for item in arr:
                values = []
                for k in all_keys:
                    val = item.get(k)
                    values.append(format_simple_value(val))
                row_indent = "  " * (indent_level + 1)
                result.append(f"{row_indent}{', '.join(values)}")
        else:
            # 简单数组
            simple_values = [format_simple_value(item) for item in arr]
            # 如果值较短，放在一行
            if sum(len(v) for v in simple_values) < 80:
                result.append(f"{indent}{key}[{len(arr)}]: {', '.join(simple_values)}")
            else:
                result.append(f"{indent}{key}[{len(arr)}]:")
                for val in simple_values:
                    row_indent = "  " * (indent_level + 1)
                    result.append(f"{row_indent}{val}")
        
        return result
    
    # 开始格式化顶层对象
    if isinstance(data, dict):
        for key, value in data.items():
            if value is None:
                lines.append(f"{key}: null")
            elif isinstance(value, bool):
                lines.append(f"{key}: {'true' if value else 'false'}")
            elif isinstance(value, (int, float)):
                lines.append(f"{key}: {value}")
            elif isinstance(value, str):
                lines.append(f"{key}: {toon_escape_value(value)}")
            elif isinstance(value, list):
                lines.extend(format_array(key, value, 0))
            elif isinstance(value, dict):
                lines.append(f"{key}:")
                obj_lines = format_object(value, 1)
                lines.extend(obj_lines.split('\n'))
    
    return '\n'.join(lines)

def read_excel_sheets(sheet_names, file_path):
    """
    读取Excel中指定sheet_name列表的数据，返回sheet名与DataFrame的字典
    """
    #Generated By AI Start (Cursor)
    dfs = {}
    xls = pd.ExcelFile(file_path)
    for sheet_name in sheet_names:
        df = xls.parse(sheet_name, header=None)
        dfs[sheet_name] = df
    return dfs
    #Generated By AI End (Cursor)

#Generated By AI Start (Cursor)
def _collect_all_cell_strings(df, max_rows=30):
    """收集DataFrame前N行所有非空单元格的字符串值，用于模糊匹配"""
    cells = []
    for col in df.columns:
        for idx, val in df[col].items():
            if idx >= max_rows:
                break
            s = str(val).strip()
            if s and s != 'nan' and s != 'None':
                cells.append((s, col, idx))
    return cells


def _fuzzy_find_keyword(df, target_str, max_rows=30):
    """
    模糊匹配关键字：先精确匹配别名列表，再用相似度匹配。
    返回 (matched_str, col, idx) 或抛出 ValueError（附带建议）。
    """
    aliases = KEYWORD_ALIASES.get(target_str, [target_str])
    cells = _collect_all_cell_strings(df, max_rows)

    for cell_str, col, idx in cells:
        if cell_str in aliases:
            return cell_str, col, idx

    best_match = None
    best_score = 0.0
    for cell_str, col, idx in cells:
        for alias in aliases:
            score = difflib.SequenceMatcher(None, cell_str, alias).ratio()
            if score > best_score:
                best_score = score
                best_match = (cell_str, col, idx)

    if best_score >= FUZZY_THRESHOLD and best_match:
        return best_match[0], best_match[1], best_match[2]

    candidates = sorted(cells, key=lambda x: max(
        difflib.SequenceMatcher(None, x[0], a).ratio() for a in aliases
    ), reverse=True)[:3]
    hint_strs = [f"'{c[0]}'" for c in candidates]
    hint = f"（相似单元格: {', '.join(hint_strs)}）" if hint_strs else ""
    raise ValueError(f"未在表格内容中找到'{target_str}'！{hint}")
#Generated By AI End (Cursor)

#Generated By AI Start (Cursor)
def _detect_layout(df, target_str):
    """
    检测布局类型并取值。
    Layout A（横向交替）：关键字与值交替排列在同一行
      例如: 主题域 | 专项分析 | 目标表英文名 | dm_xxx_d | 目标表中文名 | xxx
      特征: 关键字右侧紧跟的是非关键字的值
    Layout B（纵向表头）：关键字排列在表头行，值在下一行同列
      例如: 主题域 | 目标表英文名 | 目标表中文名
            PM     | dm_xxx_d    | xxx表
      特征: 关键字右侧紧跟的仍是关键字
    返回 (value, layout_type)
    """
    matched_str, target_col, row_idx = _fuzzy_find_keyword(df, target_str)
    col_list = list(df.columns)
    col_pos = col_list.index(target_col)

    row_data = list(df.loc[row_idx])

    all_known_keywords = set()
    for aliases in KEYWORD_ALIASES.values():
        all_known_keywords.update(aliases)

    right_val = None
    right_str = None
    if col_pos + 1 < len(col_list):
        right_val = row_data[col_pos + 1]
        if not (pd.isna(right_val) or str(right_val).strip() == "" or str(right_val).strip() == "nan"):
            right_str = str(right_val).strip()

    if right_str is not None and right_str not in all_known_keywords:
        return convert_to_serializable(right_val), "A"

    idx_list = list(df.index)
    loc = idx_list.index(row_idx)
    if loc + 1 < len(idx_list):
        next_row_idx = idx_list[loc + 1]
        next_value = df[target_col].loc[next_row_idx]
        return convert_to_serializable(next_value), "B"
    else:
        if right_str is None:
            return None, "A"
        raise ValueError(f"'{target_str}'行已是最后一行，无法获取下方内容！")
#Generated By AI End (Cursor)

def find_next_row_value(df, target_str):
    #Generated By AI Start (Cursor)
    value, _ = _detect_layout(df, target_str)
    return value
    #Generated By AI End (Cursor)

