SOURCE_HEADER_KEYWORDS = [
    "源表英文名", "源表英文名称", "源英文名",
    "源系统", "来源系统", "源表描述", "源表关联信息描述",
]

def _find_source_header_row(df, pdm_row_idx):
    """
    在PDM字段英文名行之前，搜索来源表的真正列表头行。
    列表头行的特征：同一行含有多个列标题（如"源表英文名"、"别名"、"说明"等），至少3个非空单元格。
    节标题行的特征：只有1个非空单元格（如"源表基本信息描述"），应被跳过。
    """
    idx_list = list(df.index)
    pdm_loc = idx_list.index(pdm_row_idx)

    for i in range(pdm_loc - 1, -1, -1):
        row_idx = idx_list[i]
        row = df.loc[row_idx]
        row_list = list(row)
        non_empty = [(j, str(v).strip()) for j, v in enumerate(row_list)
                     if not (pd.isna(v) or str(v).strip() == "" or str(v).strip() == "nan")]
        if len(non_empty) < 2:
            continue
        cell_strs = [s for _, s in non_empty]
        for kw in SOURCE_HEADER_KEYWORDS:
            if any(kw in c for c in cell_strs):
                return row_idx
    raise ValueError("未找到来源表列表头行")
#Generated By AI End (Cursor)

def extract_fields(df):
    #Generated By AI Start (Cursor)
    _, field_col_raw, field_start_idx = _fuzzy_find_keyword(df, 'PDM字段英文名')
    field_col = field_col_raw

    idx_list = list(df.index)
    start_i = idx_list.index(field_start_idx)

    source_table_name_attrs = []
    try:
        source_header_idx = _find_source_header_row(df, field_start_idx)
        source_i = idx_list.index(source_header_idx)

        source_header_row = df.loc[source_header_idx]
        source_header_row_list = list(source_header_row)
        source_col_map = {i: str(val).strip() for i, val in enumerate(source_header_row_list)
                          if not (pd.isna(val) or str(val).strip() == "" or str(val).strip() == "nan")}
        for idx in idx_list[source_i+1 : start_i]:
            row = df.loc[idx]
            row_list = list(row)
            if all(pd.isna(cell) or str(cell).strip() == "" for cell in row_list):
                break
            non_empty_count = sum(1 for cell in row_list if not (pd.isna(cell) or str(cell).strip() == ""))
            if non_empty_count <= 1:
                continue
            attr = {}
            for i, col_name in source_col_map.items():
                if col_name and col_name != 'nan':
                    val = row_list[i] if i < len(row_list) else None
                    if pd.isna(val) or str(val).strip() == "":
                        continue
                    attr[col_name] = convert_to_serializable(val)
            if attr:
                source_table_name_attrs.append(attr)
    except ValueError:
        pass
    #Generated By AI End (Cursor)

    # 分析字段表头
    header_idx = idx_list[start_i]
    header_row = df.loc[header_idx]
    header_row_list = list(header_row)

    # 判断首列是否为空或全空
    if pd.isna(header_row_list[0]) or str(header_row_list[0]).strip() == "":
        col_map = {i: str(val).strip() for i, val in enumerate(header_row_list[1:], start=1)}
        skip_col_indices = [0]
    else:
        col_map = {i: str(val).strip() for i, val in enumerate(header_row_list)}
        skip_col_indices = []

    # 收集字段信息：从header_idx的下一行开始
    fields = []
    for offset in range(start_i + 1, len(idx_list)):
        row_idx = idx_list[offset]
        row = df.loc[row_idx]
        row_list = list(row)
        # 如果这一行全为空，认为到达结尾
        if all([pd.isna(cell) or str(cell).strip() == "" for cell in row_list]):
            break
        field = {}
        for i, col_name in col_map.items():
            if col_name:
                val = row_list[i] if i < len(row_list) else None
                field[col_name] = convert_to_serializable(val)
        fields.append(field)
    return fields, source_table_name_attrs

